// Replace with Google Calendar API HTTP Request for production
const events = [
  { title: 'Sprint Planning', day: 'Monday', start: '09:00', end: '11:00', category: 'engineering', attendees: 8, recurring: false },
  { title: 'CEO 1:1', day: 'Monday', start: '14:00', end: '14:30', category: 'internal', attendees: 2, recurring: true },
  { title: 'Customer Discovery Call', day: 'Tuesday', start: '10:00', end: '11:00', category: 'customer', attendees: 3, recurring: false },
  { title: 'Design Review', day: 'Tuesday', start: '14:00', end: '15:00', category: 'internal', attendees: 4, recurring: true },
  { title: 'All Hands', day: 'Wednesday', start: '12:00', end: '13:00', category: 'company', attendees: 45, recurring: true },
  { title: 'PM Sync', day: 'Wednesday', start: '15:00', end: '16:00', category: 'internal', attendees: 3, recurring: true },
  { title: 'Candidate Interview', day: 'Thursday', start: '10:00', end: '11:00', category: 'recruiting', attendees: 2, recurring: false },
  { title: 'Stakeholder Update', day: 'Thursday', start: '14:00', end: '15:00', category: 'internal', attendees: 6, recurring: false },
  { title: 'Team Retro', day: 'Friday', start: '10:00', end: '11:00', category: 'team', recurring: true, attendees: 8 }
];
const config = { work_day_hours: 8, work_days: 5, focus_threshold_pct: 40, min_focus_block_hours: 2 };
return [{ json: { events, config, week: 'July 14–18, 2026' } }];

const { events, config, week } = $input.first().json;
const getDuration = (start, end) => { const [sh,sm] = start.split(':').map(Number); const [eh,em] = end.split(':').map(Number); return (eh*60+em-sh*60-sm)/60; };
const total_meeting_hours = events.reduce((s,e) => s + getDuration(e.start, e.end), 0);
const total_available = config.work_day_hours * config.work_days;
const focus_hours = total_available - total_meeting_hours;
const focus_pct = parseFloat(((focus_hours / total_available)*100).toFixed(1));
const below_threshold = focus_pct < config.focus_threshold_pct;
const by_category = {};
events.forEach(e => { by_category[e.category] = (by_category[e.category]||0) + getDuration(e.start,e.end); });
const recurring_hours = events.filter(e=>e.recurring).reduce((s,e) => s + getDuration(e.start,e.end), 0);
const one_off_hours = total_meeting_hours - recurring_hours;
const by_day = {};
events.forEach(e => { if(!by_day[e.day]) by_day[e.day]={hours:0,events:[]}; by_day[e.day].hours += getDuration(e.start,e.end); by_day[e.day].events.push(e.title); });
const heaviest_day = Object.entries(by_day).sort((a,b)=>b[1].hours-a[1].hours)[0];
const suggestions = [];
if (below_threshold) suggestions.push(`Focus time is ${focus_pct}% (below ${config.focus_threshold_pct}% threshold) — consider declining or shortening ${Object.entries(by_category).sort((a,b)=>b[1]-a[1])[0][0]} meetings`);
if (recurring_hours > total_meeting_hours * 0.7) suggestions.push(`${Math.round((recurring_hours/total_meeting_hours)*100)}% of meeting time is recurring — review each recurring meeting this week for necessity`);
if (heaviest_day[1].hours > 5) suggestions.push(`${heaviest_day[0]} is the heaviest day (${heaviest_day[1].hours}h in meetings) — protect mornings for focus work on ${Object.keys(by_day).find(d=>!by_day[d] || by_day[d].hours < 2) || 'lighter days'}`);
const free_days = ['Monday','Tuesday','Wednesday','Thursday','Friday'].filter(d => !by_day[d] || by_day[d].hours < 2);
if (free_days.length > 0) suggestions.push(`${free_days.join(' and ')} ${free_days.length>1?'are':'is'} light — schedule deep work blocks`);
return [{ json: { events, config, week, metrics: { total_meeting_hours, total_available, focus_hours, focus_pct, below_threshold, recurring_hours, one_off_hours }, by_category, by_day, heaviest_day: heaviest_day[0], suggestions } }];

const { metrics: m, by_category, by_day, heaviest_day, suggestions, week } = $input.first().json;
const catLines = Object.entries(by_category).sort((a,b)=>b[1]-a[1]).map(([k,v]) => `  ${k}: ${v}h`).join('\n');
const dayLines = ['Monday','Tuesday','Wednesday','Thursday','Friday'].map(d => { const data = by_day[d]; return data ? `  ${d}: ${data.hours}h meetings — ${data.events.join(', ')}` : `  ${d}: no meetings`; }).join('\n');
const report = [
  `CALENDAR AUDIT: ${week}`,
  `Meeting load: ${m.total_meeting_hours}h / ${m.total_available}h total | Focus: ${m.focus_hours}h (${m.focus_pct}%)${m.below_threshold ? ' ⚠️ BELOW THRESHOLD' : ' ✅'}`,
  `Recurring: ${m.recurring_hours}h | One-off: ${m.one_off_hours}h`,
  `Heaviest day: ${heaviest_day}`,
  ``,
  `BY DAY:`,
  dayLines,
  ``,
  `BY CATEGORY:`,
  catLines,
  ``,
  `RECOMMENDATIONS:`,
  ...suggestions.map(s => `  • ${s}`),
].join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
